def contains_tokens_near(n, token1, token2, window=10):
    words = n.split()
    positions1 = [i for i,w in enumerate(words) if w == token1]
    positions2 = [i for i,w in enumerate(words) if w == token2]
    for i in positions1:
        for j in positions2:
            if abs(i-j) <= window:
                return True
    return False

